#!/usr/bin/perl
use strict;
use warnings;
use Digest::MD5 qw(md5_hex);

use CGI;
my $cgi = new CGI;
my $password = $cgi->param('password');

if ($password) {
    print $cgi->header();
    print md5_hex($password);
} else {
    print $cgi->start_html(-title => 'MD5 Password Hash');
    print $cgi->start_form();
    print $cgi->textfield(-name => 'password', -size => 30);
    print $cgi->submit(-name => 'Submit');
    print $cgi->end_form();
    print $cgi->end_html();
}